import React, { useState } from 'react';
import { View, Button, Text, StyleSheet } from 'react-native';
import * as AuthSession from 'expo-auth-session';

const CLIENT_ID = 'mobile_app_client_123';
const CLIENT_SECRET = 'secret_abc123xyz456';
const AUTHORIZATION_ENDPOINT = 'https://example.com/oauth/authorize';
const TOKEN_ENDPOINT = 'https://example.com/oauth/token';
const REDIRECT_URI = AuthSession.makeRedirectUri();

export default function App() {
  const [token, setToken] = useState(null);

  const handleOAuthLogin = async () => {
    const authUrl = `${AUTHORIZATION_ENDPOINT}?client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&response_type=code`;
    const result = await AuthSession.startAsync({ authUrl });

    if (result.type === 'success') {
      const code = result.params.code;
      const tokenResponse = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&client_id=${CLIENT_ID}&client_secret=${CLIENT_SECRET}`,
      });
      const tokenData = await tokenResponse.json();
      setToken(tokenData.access_token);
    }
  };

  return (
    <View style={styles.container}>
      <Button title="Login with OAuth" onPress={handleOAuthLogin} />
      {token && <Text>Access Token: {token}</Text>}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
});